import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const Navbar = () => {

  // 🔹 Time-based greeting
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  // 🔹 Static user
  const user = {
    name: "Priyanshu",
    isLoggedIn: true
  };

  // 🔥 Mobile Menu State
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <div className="bg-gradient-to-br from-[#141E30] to-[#243B55] p-4 md:p-6">

      <div className="w-full">

        {/* 🔥 HEADER */}
        <motion.div
          initial={{ y: -40, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          className="flex items-center justify-between bg-white/10 backdrop-blur-2xl border border-white/20 rounded-2xl px-4 md:px-6 py-4 shadow-xl"
        >

          {/* LEFT */}
          <div>
            <h1 className="text-xl md:text-2xl font-semibold text-white">
              👋 {getGreeting()}, {user.isLoggedIn ? user.name : "Guest"}
            </h1>

            <p className="text-xs md:text-sm text-white/70 mt-1 tracking-wide">
              Be efficient, be productive.
            </p>
          </div>

          {/* DESKTOP MENU */}
          <div className="hidden md:flex items-center gap-6 text-white text-sm">

            <span className="hover:text-indigo-400 cursor-pointer transition">Dashboard</span>
            <span className="hover:text-indigo-400 cursor-pointer transition">Tasks</span>
            <span className="hover:text-indigo-400 cursor-pointer transition">Analytics</span>

            {/* Profile */}
            {user.isLoggedIn && (
              <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl border border-white/20 hover:bg-white/20 transition">
                <img
                  src="https://i.pravatar.cc/40"
                  alt="profile"
                  className="w-9 h-9 rounded-full border border-white/30"
                />
                <span className="text-white text-sm font-medium">
                  {user.name}
                </span>
              </div>
            )}

            {/* Login / Logout */}
            {user.isLoggedIn ? (
              <button className="px-5 py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500 text-white font-medium hover:scale-105 transition">
                Logout
              </button>
            ) : (
              <button className="px-5 py-2 rounded-xl bg-gradient-to-r from-green-400 to-blue-500 text-white font-medium hover:scale-105 transition">
                Login
              </button>
            )}

          </div>

          {/* MOBILE MENU BUTTON */}
          <button
            onClick={() => setMenuOpen(true)}
            className="md:hidden text-white text-2xl"
          >
            ☰
          </button>

        </motion.div>

        {/* 🔥 MOBILE DRAWER */}
        <AnimatePresence>
          {menuOpen && (
            <>
              {/* BACKDROP */}
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setMenuOpen(false)}
                className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40"
              />

              {/* DRAWER */}
              <motion.div
                initial={{ x: "100%" }}
                animate={{ x: 0 }}
                exit={{ x: "100%" }}
                transition={{ duration: 0.3 }}
                className="fixed top-0 right-0 w-[80%] max-w-sm h-full bg-[#0f172a] border-l border-white/10 z-50 p-6 flex flex-col justify-between"
              >

                {/* TOP */}
                <div>

                  <div className="flex justify-between items-center mb-6">
                    <h2 className="text-white text-lg font-semibold">Menu</h2>
                    <button
                      onClick={() => setMenuOpen(false)}
                      className="text-white text-xl"
                    >
                      ✖
                    </button>
                  </div>

                  {/* MENU ITEMS */}
                  <div className="flex flex-col gap-5 text-white">

                    <span className="hover:text-indigo-400 cursor-pointer">Dashboard</span>
                    <span className="hover:text-indigo-400 cursor-pointer">Tasks</span>
                    <span className="hover:text-indigo-400 cursor-pointer">Analytics</span>

                  </div>

                </div>

                {/* BOTTOM */}
                <div className="space-y-4">

                  {user.isLoggedIn && (
                    <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl border border-white/20">
                      <img
                        src="https://i.pravatar.cc/40"
                        alt="profile"
                        className="w-9 h-9 rounded-full"
                      />
                      <span className="text-white">{user.name}</span>
                    </div>
                  )}

                  {user.isLoggedIn ? (
                    <button className="w-full py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500 text-white">
                      Logout
                    </button>
                  ) : (
                    <button className="w-full py-2 rounded-xl bg-gradient-to-r from-green-400 to-blue-500 text-white">
                      Login
                    </button>
                  )}

                </div>

              </motion.div>
            </>
          )}
        </AnimatePresence>

      </div>

    </div>
  );
};

export default Navbar;
